from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Use the first subject as the main subject
    main_subject = triples[0].subject if triples else ""
    details = []

    for triple in triples:
        predicate = triple.predicate
        obj = triple.object

        if predicate == "cityServed":
            details.append(f"serves the city of {obj}")
        elif predicate == "mayor":
            details.append(f"The mayor of {main_subject} is {obj}")
        elif predicate == "isPartOf":
            details.append(f"is part of {obj}")
        elif predicate == "operatingOrganisation":
            details.append(f"is operated by {obj}")
        elif predicate == "location":
            details.append(f"is located in {obj}")
        elif predicate == "elevationAboveTheSeaLevel":
            details.append(f"has an elevation of {obj} metres above sea level")
        elif predicate == "runwayLength":
            details.append(f"has a runway length of {obj} metres")
        elif predicate == "country":
            details.append(f"is in the country of {obj}")
        elif predicate == "capital":
            details.append(f"has a capital of {obj}")
        elif predicate == "language":
            details.append(f"{obj} is spoken in {main_subject}")
        elif predicate == "leader":
            details.append(f"The leader of {main_subject} is {obj}")
        elif predicate == "owner":
            details.append(f"is owned by {obj}")
        elif predicate == "1stRunwayLengthFeet":
            details.append(f"has a first runway length of {obj} feet")
        elif predicate == "1stRunwaySurfaceType":
            details.append(f"has a first runway surface type of {obj}")
        elif predicate == "3rdRunwayLengthFeet":
            details.append(f"has a third runway length of {obj} feet")
        elif predicate == "icaoLocationIdentifier":
            details.append(f"has an ICAO location identifier of {obj}")
        elif predicate == "locationIdentifier":
            details.append(f"{main_subject} location identifier is {obj}")
        elif predicate == "elevationAboveTheSeaLevelInFeet":
            details.append(f"has an elevation of {obj} feet above sea level")
        elif predicate == "iataLocationIdentifier":
            details.append(f"{main_subject} IATA identifier is {obj}")
        elif predicate == "nativeName":
            details.append(f"has a native name of {obj}")
        elif predicate == "leaderParty":
            details.append(f"has a leader party of {obj}")
        elif predicate == "runwayName":
            details.append(f"The runway name of {main_subject} is {obj}")
        elif predicate == "runwaySurfaceType":
            details.append(f"has a runway surface type of {obj}")
        elif predicate == "elevationAboveTheSeaLevelInMetres":
            details.append(f"has an elevation of {obj} metres above sea level")
        elif predicate == "demonym":
            details.append(f"whose people are called {obj}")
        else:
            # Handle other predicates with more natural phrasing
            normalized_pred = predicate.replace('1stRunway', 'first runway').replace('2ndRunway', 'second runway').replace('3rdRunway', 'third runway').replace('4thRunway', 'fourth runway').replace('5thRunway', 'fifth runway').replace('Length', ' length').replace('SurfaceType', ' surface type').replace('AboveTheSeaLevel', ' above sea level').replace('LocationIdentifier', ' identifier').replace('Iata', 'IATA').replace('Icao', 'ICAO')
            if "runway" in predicate or "elevation" in predicate:
                if "Length" in predicate:
                    if "Feet" in predicate:
                        details.append(f"has a {normalized_pred} of {obj} feet")
                    else:
                        details.append(f"has a {normalized_pred} of {obj} metres")
                else:
                    details.append(f"has {normalized_pred} of {obj}")
            else:
                details.append(f"has a {normalized_pred} of {obj}")

    # Build a single coherent sentence
    if details:
        result = f"{main_subject} " + ", ".join(details)
    else:
        result = main_subject

    return result + "."

